  displayErrorMessage() {
    if (this.showErrors()) {
      const firstErrorKey = Object.keys(this.control().errors!)[0];
      return this.errorMessages()[firstErrorKey] || 'Invalid input';
    }
    return 'Unknown error';
  }
}

